// ── Shared Types ────────────────────────────────────────────────────────────

export type TaskStatus = 'todo' | 'in-progress' | 'blocked' | 'review' | 'done' | 'skipped';

export interface TaskResponse {
  id: string;
  shortId: number;
  moduleId: string;
  title: string;
  description: string | null;
  references: string | null;
  status: TaskStatus;
  assignee: string | null;
  subTotal: number;
  subDone: number;
  progressMessage: string | null;
  blockedReason: string | null;
  commitHash: string | null;
  createdAt: string;
  updatedAt: string;
  reportedAt: string | null;
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { parseTaskId, resolveTaskId } from '../utils/id.js';
import { outputJson, outputJsonError } from '../utils/json-output.js';

export function registerCompleteCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('complete <taskId>')
    .description('完成任务')
    .option('--message <msg>', '完成说明')
    .option('--commit <hash>', '关联的 Git 提交哈希')
    .option('--json', '以 JSON 格式输出')
    .action(async (taskId: string, opts: { message?: string; commit?: string; json?: boolean }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      try {
        const parsed = parseTaskId(taskId);
        const fullId = await resolveTaskId(parsed, () =>
          client.get<TaskResponse[]>(`/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`),
        );

        const body: Record<string, unknown> = {};
        if (opts.message) body.progressMessage = opts.message;
        if (opts.commit) body.commitHash = opts.commit;

        const result = await client.post<TaskResponse>(`/api/tasks/${encodeURIComponent(fullId)}/complete`, body);

        if (opts.json) {
          outputJson(result);
          return;
        }

        console.log(`✓ 已完成 #${result.shortId}「${result.title}」`);
        console.log(`  状态: 已完成`);
        if (result.commitHash) {
          console.log(`  提交: ${result.commitHash}`);
        }
        if (result.progressMessage) {
          console.log(`  说明: ${result.progressMessage}`);
        }
      } catch (err) {
        if (opts.json) {
          outputJsonError(err);
        }
        if (err instanceof Error) {
          console.error(err.message);
        }
        process.exit(1);
      }
    });
}

import { eq, asc } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { modules, milestones } from '$lib/db/schema.js';
import type { CreateModuleInput, UpdateModuleInput } from '$lib/schemas/index.js';

/** Body data for createModule (milestoneId comes from URL param). */
type CreateModuleBody = Omit<CreateModuleInput, 'milestoneId'>;

// ── ID Generation ────────────────────────────────────────────────────────────

/** Generate MOD-{milestone_seq}-{next_seq} ID. */
export async function nextModuleId(
	db: BetterSQLite3Database<any>,
	milestoneId: string
): Promise<string> {
	const msSeq = milestoneId.replace('MS-', '');
	const rows = await db
		.select({ id: modules.id })
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.all();
	let maxSeq = 0;
	for (const row of rows) {
		// Format: MOD-{msSeq}-{seq}
		const parts = row.id.split('-');
		const seq = parseInt(parts[parts.length - 1], 10);
		if (seq > maxSeq) maxSeq = seq;
	}
	return `MOD-${msSeq}-${maxSeq + 1}`;
}

// ── Create ───────────────────────────────────────────────────────────────────

export async function createModule(
	db: BetterSQLite3Database<any>,
	milestoneId: string,
	data: CreateModuleBody
) {
	// Verify milestone exists
	const ms = await db.select().from(milestones).where(eq(milestones.id, milestoneId)).get();
	if (!ms) return null;

	const id = await nextModuleId(db, milestoneId);
	const result = await db
		.insert(modules)
		.values({
			id,
			milestoneId,
			name: data.name,
			description: data.description ?? null,
			sortOrder: data.sortOrder ?? 0
		})
		.returning()
		.get();
	return formatModuleResponse(result);
}

// ── List by Milestone ────────────────────────────────────────────────────────

export async function listModulesByMilestone(
	db: BetterSQLite3Database<any>,
	milestoneId: string
) {
	const rows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.orderBy(asc(modules.sortOrder))
		.all();
	return rows.map(formatModuleResponse);
}

// ── Update ───────────────────────────────────────────────────────────────────

export async function updateModule(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateModuleInput
) {
	const existing = await db.select().from(modules).where(eq(modules.id, id)).get();
	if (!existing) return null;

	const updates: Record<string, any> = {};
	if (data.name !== undefined) updates.name = data.name;
	if (data.description !== undefined) updates.description = data.description ?? null;
	if (data.status !== undefined) updates.status = data.status;
	if (data.sortOrder !== undefined) updates.sortOrder = data.sortOrder;

	if (Object.keys(updates).length === 0) {
		return formatModuleResponse(existing);
	}

	const result = await db
		.update(modules)
		.set(updates)
		.where(eq(modules.id, id))
		.returning()
		.get();
	return formatModuleResponse(result);
}

// ── Formatter ────────────────────────────────────────────────────────────────

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

/**
 * Integration-style tests for --json output across all 7 CLI commands.
 *
 * Strategy:
 * - Mock globalThis.fetch to return controlled API responses.
 * - Create a Commander program per test, register the command, and call
 *   the action handler directly (avoids process.exit from Commander).
 * - Spy on process.stdout.write to capture JSON output.
 * - Stub process.exit so outputJsonError doesn't kill the test runner.
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import type { TaskResponse } from '../types.js';
import { MtCliError } from '../client.js';

// ── Test Fixtures ───────────────────────────────────────────────────────────

const mockTask1: TaskResponse = {
